+const transactionalReloadStateFile = "reload-status.json"
+
+type transactionalReload struct {
+	mu       sync.RWMutex
+	lastGood *config.Config
+	status   api_v1.ReloadStatus
+	path     string
+	logger   *slog.Logger
+}
+
+func newTransactionalReload(storagePath string, logger *slog.Logger) *transactionalReload {
+	t := &transactionalReload{
+		path:   filepath.Join(storagePath, transactionalReloadStateFile),
+		logger: logger,
+		status: emptyReloadStatus(),
+	}
+
+	b, err := os.ReadFile(t.path)
+	if err != nil {
+		if !os.IsNotExist(err) {
+			logger.Warn("Unable to read persisted transactional reload status", "err", err)
+		}
+		return t
+	}
+	if err := json.Unmarshal(b, &t.status); err != nil {
+		logger.Warn("Unable to parse persisted transactional reload status", "err", err)
+		t.status = emptyReloadStatus()
+		return t
+	}
+	t.normalizeStatus()
+	return t
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{
+		ErrorCategory:     "none",
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]float64{},
+	}
+}
+
+func (t *transactionalReload) normalizeStatus() {
+	if t.status.AppliedReloaders == nil {
+		t.status.AppliedReloaders = []string{}
+	}
+	if t.status.ReloaderTimingsMS == nil {
+		t.status.ReloaderTimingsMS = map[string]float64{}
+	}
+	if t.status.ErrorCategory == "" {
+		t.status.ErrorCategory = "none"
+	}
+}
+
+func (t *transactionalReload) Status() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	status := t.status
+	status.AppliedReloaders = append([]string(nil), t.status.AppliedReloaders...)
+	status.ReloaderTimingsMS = make(map[string]float64, len(t.status.ReloaderTimingsMS))
+	for name, timing := range t.status.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[name] = timing
+	}
+	return status
+}
+
+func (t *transactionalReload) setInitialConfig(conf *config.Config) {
+	t.mu.Lock()
+	defer t.mu.Unlock()
+	t.lastGood = conf
+}
+
+func (t *transactionalReload) apply(conf *config.Config, rls []reloader, record bool) error {
+	status := api_v1.ReloadStatus{
+		LastReloadID:      time.Now().UTC().Format(time.RFC3339Nano),
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]float64{},
+	}
+
+	for _, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = float64(time.Since(start)) / float64(time.Millisecond)
+		if err == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+
+		status.LastReloadSuccessful = false
+		status.ErrorCategory = "apply_error"
+		status.ErrorMessage = err.Error()
+		status.FailedReloader = rl.name
+
+		if len(status.AppliedReloaders) > 0 {
+			status.RollbackAttempted = true
+			t.mu.RLock()
+			lastGood := t.lastGood
+			t.mu.RUnlock()
+			if lastGood != nil {
+				rollbackErr := t.rollback(lastGood, rls)
+				status.RollbackSuccessful = rollbackErr == nil
+				if rollbackErr != nil {
+					status.ErrorCategory = "rollback_error"
+					status.ErrorMessage = fmt.Sprintf("apply %s: %v; rollback: %v", rl.name, err, rollbackErr)
+				}
+			}
+		}
+		if record {
+			t.record(status)
+		}
+		return fmt.Errorf("failed to apply configuration in reloader %q: %w", rl.name, err)
+	}
+
+	status.LastReloadSuccessful = true
+	status.ErrorCategory = "none"
+	t.mu.Lock()
+	t.lastGood = conf
+	t.mu.Unlock()
+	if record {
+		t.record(status)
+	}
+	return nil
+}
+
+func (t *transactionalReload) rollback(conf *config.Config, rls []reloader) error {
+	var errs []error
+	for _, rl := range rls {
+		if err := rl.reloader(conf); err != nil {
+			errs = append(errs, fmt.Errorf("%s: %w", rl.name, err))
+		}
+	}
+	return fmt.Errorf("%w", errors.Join(errs...))
+}
+
+func (t *transactionalReload) record(status api_v1.ReloadStatus) {
+	t.mu.Lock()
+	t.status = status
+	t.mu.Unlock()
+
+	b, err := json.Marshal(status)
+	if err != nil {
+		t.logger.Warn("Unable to marshal transactional reload status", "err", err)
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(t.path), 0o755); err != nil {
+		t.logger.Warn("Unable to create transactional reload status directory", "err", err)
+		return
+	}
+	tmp, err := os.CreateTemp(filepath.Dir(t.path), ".reload-status-*")
+	if err != nil {
+		t.logger.Warn("Unable to create transactional reload status file", "err", err)
+		return
+	}
+	tmpName := tmp.Name()
+	defer os.Remove(tmpName)
+	if _, err := tmp.Write(b); err != nil {
+		tmp.Close()
+		t.logger.Warn("Unable to write transactional reload status", "err", err)
+		return
+	}
+	if err := tmp.Close(); err != nil {
+		t.logger.Warn("Unable to close transactional reload status", "err", err)
+		return
+	}
+	if err := os.Rename(tmpName, t.path); err != nil {
+		t.logger.Warn("Unable to persist transactional reload status", "err", err)
+	}
+}
